import numpy as np

class KMeans:
    def __init__(self, n_clusters: int, max_iter: int = 300, seed: int = None):
        self.n_clusters = n_clusters
        self.max_iter = max_iter
        self.seed = seed
        self.cluster_centers_ = None
        self.labels_ = None
        self.inertia_ = None

    def _assign(self, X, centroids):
        dists = np.sum((X[:, None, :] - centroids[None, :, :]) ** 2, axis=2)  # (N, K)
        return np.argmin(dists, axis=1)

    def fit(self, X: np.ndarray) -> 'KMeans':
        rng = np.random.default_rng(self.seed)
        N, D = X.shape
        K = self.n_clusters

        # Initialize centroids
        indices = rng.choice(N, size=K, replace=False)
        centroids = X[indices].copy()

        for _ in range(self.max_iter):
            labels = self._assign(X, centroids)
            new_centroids = np.zeros((K, D))
            for k in range(K):
                mask = labels == k
                if mask.sum() == 0:
                    new_centroids[k] = X[rng.integers(0, N)]
                else:
                    new_centroids[k] = X[mask].mean(axis=0)
            if np.allclose(new_centroids, centroids):
                break
            centroids = new_centroids

        self.cluster_centers_ = centroids
        self.labels_ = self._assign(X, centroids)
        self.inertia_ = float(np.sum(
            np.sum((X - centroids[self.labels_]) ** 2, axis=1)
        ))
        return self

    def predict(self, X: np.ndarray) -> np.ndarray:
        return self._assign(X, self.cluster_centers_)

    def fit_predict(self, X: np.ndarray) -> np.ndarray:
        return self.fit(X).labels_
